// GTM Domain Agent v2 — Fixed gateway field names
const input = $input.first().json;
const body = input.body || input;
const goal = body.goal;
const tenant_id = body.tenant_id || $vars.DEFAULT_TENANT_ID || 'kahuna';
const context = body.context || {};
if (!goal) { return [{ json: { error: 'Missing required field: goal', tenant_id } }]; }
const N8N_BASE = 'https://mmurawala.app.n8n.cloud';
const N8N_API_KEY = $vars.N8N_API_KEY;
const ANTHROPIC_API_KEY = $vars.ANTHROPIC_API_KEY_N8N;
const GW_MASTER_KEY = $vars.key_master;
const ACTION_MAP_TABLE = 'nTBOiE9byj3KcHVQ';
const GW_PATH = '/webhook/orchestrate-v2';
const MODEL = 'claude-sonnet-4-6';
const MAX_TURNS = 15;
const actionMapResp = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_BASE}/api/v1/data-tables/${ACTION_MAP_TABLE}/rows?limit=250`, headers: { 'X-N8N-API-KEY': N8N_API_KEY }, json: true });
const actionMap = (actionMapResp.data || actionMapResp.rows || []);
const validActions = new Set(actionMap.map(r => `${r.api_name}.${r.action}`));
const systemPrompt = `You are the Ascend GTM Domain Agent — an AI assistant that executes marketing, sales, analytics, and productivity tasks through the Ascend Gateway platform.
You serve tenant: "${tenant_id}"

## HOW THE PLATFORM WORKS
- You call the ascend_gateway tool with {api_name, action, params}
- The gateway automatically resolves tenant config and injects account IDs (customer_id, property_id, ad_account_id, etc.) from tenant_metadata
- You do NOT need to know or pass internal account IDs
- For most queries, you just need the api_name, action, and any query-specific params

## CRITICAL RULES
1. NEVER ask the user for account IDs, customer IDs, or property IDs
2. ALWAYS use the think tool first to plan multi-step queries
3. When a query spans multiple domains, make parallel gateway calls
4. Summarize data in a human-readable format — never dump raw JSON
5. If a gateway call returns an error, explain what went wrong
6. Default date range is LAST_7_DAYS unless the user specifies otherwise

## AVAILABLE DOMAINS & KEY ACTIONS
### Advertising
- google_ads: campaigns, ad_groups, keywords, custom_query (GAQL), mutate
- meta_ads: campaigns, ad_sets, insights
- linkedin_ads: campaigns, analytics, creatives
### Analytics
- ga4: report, realtime, performance, list_streams
- google_search_console: query, performance, sitemaps
### CRM
- hubspot: contacts, companies, deals, search, get, create, update, pipelines, owners, tasks, tickets, properties
- salesforce: query (SOQL), get, create, update, describe, search, limits
- apollo: search, enrich, organization_search
- gong: calls, call_transcript, users, stats
### Marketing / Content
- wordpress: posts, get_post, create_post, update_post, pages, categories, media
- semrush: domain_overview, keyword_overview, backlinks, organic_results
### Productivity
- google_sheets: read, write, append, list, clear, create
- google_calendar: list, create, get, update, delete, free_busy
- google_drive: list, get, search, create, copy, move, delete, download
- google_docs: get, create, append
- gmail: send, list, read, draft, search, reply, trash, threads
- outlook: send, list, read, search, calendar_events
- slack: send, list_channels, search, read_channel, read_thread
- notion: search, get_page, create_page, update_page, query_database
### AI
- anthropic: messages | openai: chat, images | gemini: generate, image, search
- groq: chat | perplexity: chat | deepseek: chat
### Creative
- leonardo: generate, status | gamma: generate, status

## PARAM HINTS
- ga4.report: {metrics:[{name:'sessions'},{name:'totalUsers'}],dimensions:[{name:'date'}],dateRanges:[{startDate:'7daysAgo',endDate:'today'}]}
- google_ads.campaigns: {date_range:'LAST_7_DAYS'}
- google_ads.custom_query: {gaql:'SELECT campaign.name, metrics.clicks FROM campaign WHERE ...'}
- meta_ads.insights: {fields:'impressions,clicks,spend,ctr',date_preset:'last_7d',level:'campaign'}
- hubspot.search: {objectType:'contacts',filters:[{propertyName:'email',operator:'CONTAINS_TOKEN',value:'@example.com'}]}
- salesforce.query: {soql:'SELECT Id, Name FROM Account LIMIT 10'}
- google_search_console.query: {dimensions:['query'],rowLimit:25}
- slack.send: {channel:'#channel-name',text:'Hello!'}
- wordpress.posts: {per_page:10,status:'publish'}

Always be concise, action-oriented, and format responses for readability.`;
const tools = [{ name: 'think', description: 'Plan your approach. ALWAYS use first for complex queries.', input_schema: { type: 'object', properties: { thought: { type: 'string' } }, required: ['thought'] } }, { name: 'ascend_gateway', description: 'Execute a GTM action. Gateway auto-injects tenant account IDs.', input_schema: { type: 'object', properties: { api_name: { type: 'string' }, action: { type: 'string' }, params: { type: 'object' } }, required: ['api_name', 'action'] } }, { name: 'list_domain_actions', description: 'Discover actions not in built-in catalog.', input_schema: { type: 'object', properties: { api_name: { type: 'string' } } } }];
async function executeTool(name, toolInput) {
  if (name === 'think') return JSON.stringify({ noted: true });
  if (name === 'list_domain_actions') { const filtered = toolInput.api_name ? actionMap.filter(r => r.api_name === toolInput.api_name) : actionMap; return JSON.stringify(filtered.map(r => ({ api_name: r.api_name, action: r.action, description: r.description || '' }))); }
  if (name === 'ascend_gateway') {
    const apiName = toolInput.api_name; const action = toolInput.action; const key = `${apiName}.${action}`;
    if (!validActions.has(key)) { const apiExists = actionMap.some(r => r.api_name === apiName); if (!apiExists) return JSON.stringify({ error: `Unknown API: ${apiName}` }); return JSON.stringify({ error: `Unknown action: ${action} for ${apiName}`, available: [...new Set(actionMap.filter(r => r.api_name === apiName).map(r => r.action))] }); }
    try { const gwResp = await this.helpers.httpRequest({ method: 'POST', url: `${N8N_BASE}${GW_PATH}`, headers: { 'Content-Type': 'application/json', 'x-api-key': GW_MASTER_KEY }, body: { domain: apiName, action, client: tenant_id, params: toolInput.params || {} }, json: true, timeout: 30000 }); const s = JSON.stringify(gwResp); if (s.length > 15000) { const d = gwResp.data || gwResp.result || gwResp; const items = Array.isArray(d) ? d : (d.rows || d.results || d.items || [d]); return JSON.stringify({ _truncated: true, _total: items.length, data: items.slice(0, 20) }); } return s; } catch (e) { return JSON.stringify({ error: e.message || String(e) }); }
  }
  return JSON.stringify({ error: `Unknown tool: ${name}` });
}
let messages = [{ role: 'user', content: goal }];
if (context.history && Array.isArray(context.history)) { messages = [...context.history, { role: 'user', content: goal }]; }
let finalResponse = ''; let totalTokens = { input: 0, output: 0 };
for (let turn = 0; turn < MAX_TURNS; turn++) {
  const result = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.anthropic.com/v1/messages', headers: { 'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01' }, body: { model: MODEL, max_tokens: 4096, system: systemPrompt, tools, messages }, json: true });
  if (result.error) throw new Error(`Anthropic error: ${JSON.stringify(result.error)}`);
  if (result.usage) { totalTokens.input += result.usage.input_tokens || 0; totalTokens.output += result.usage.output_tokens || 0; }
  messages.push({ role: 'assistant', content: result.content });
  if (result.stop_reason === 'end_turn') { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('
'); break; }
  const toolUseBlocks = result.content.filter(b => b.type === 'tool_use');
  if (toolUseBlocks.length === 0) { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('
'); break; }
  const toolResults = [];
  for (const tu of toolUseBlocks) { const tr = await executeTool.call(this, tu.name, tu.input); toolResults.push({ type: 'tool_result', tool_use_id: tu.id, content: tr }); }
  messages.push({ role: 'user', content: toolResults });
}
return [{ json: { response: finalResponse, tenant_id, goal, turns: Math.floor(messages.length / 2), tokens: totalTokens } }];
